{
  "events": [
    {
      "id": "viper_strike",
      "day": 1,
      "time": "0600",
      "name": "Viper Strike",
      "name_zh": "毒蛇打击",
      "type": "assassination",
      "trigger": "game_start",

      "location": "neutral_zone",
      "perpetrator": "phoenix_state",
      "target": "mountain_republic",

      "description": "Phoenix State special forces eliminate Mountain Republic general Rashid al-Zahir in a precision strike on a neutral zone safehouse. Western Alliance confirms intelligence support.",

      "description_zh": "凤凰国特种部队在中立区安全屋精准击杀山岳共和国将军Rashid al-Zahir。西方联盟确认提供情报支持。",

      "casualties": {
        "target_killed": "Rashid al-Zahir (MR Highland Corps Commander)",
        "collateral": 2,
        "ps_forces": 0
      },

      "global_reaction": {
        "mountain_republic": "declares 'thunder and fire' retaliation",
        "western_alliance": "defends action as counter-terrorism",
        "eastern_coalition": "calls for restraint",
        "un": "emergency security council meeting"
      },

      "consequences": {
        "mr_public_approval": -15,
        "ps_threat_level": "+high",
        "wa_diplomatic_cost": -20,
        "escalation_risk": "+30%"
